require 'sendgrid-ruby'

class SendGridMailer < ApplicationMailer
  include SendGrid

  default from: ENV.fetch('SENDGRID_FROM_EMAIL', 'noreply@example.com')

  def welcome_email(user)
    @user = user
    if use_sendgrid?
      send_via_sendgrid(
        to: @user.email,
        subject: 'Welcome to Our Application',
        template_id: ENV['SENDGRID_WELCOME_TEMPLATE_ID'],
        dynamic_template_data: {
          first_name: @user.first_name,
          login_url: login_url
        }
      )
    else
      mail(to: @user.email, subject: 'Welcome to Our Application')
    end
  end

  def password_reset_email(user, reset_token)
    @user = user
    @reset_token = reset_token
    if use_sendgrid?
      send_via_sendgrid(
        to: @user.email,
        subject: 'Password Reset Instructions',
        template_id: ENV['SENDGRID_PASSWORD_RESET_TEMPLATE_ID'],
        dynamic_template_data: {
          first_name: @user.first_name,
          reset_url: edit_password_reset_url(@reset_token)
        }
      )
    else
      mail(to: @user.email, subject: 'Password Reset Instructions')
    end
  end

  def notification_email(user, message, options = {})
    @user = user
    @message = message
    @options = options

    if use_sendgrid?
      send_via_sendgrid(
        to: @user.email,
        subject: options.fetch(:subject, 'New Notification'),
        html_content: render_to_string(template: 'send_grid_mailer/notification_email'),
        plain_content: @message,
        categories: options.fetch(:categories, ['notification']),
        custom_args: options.fetch(:custom_args, {})
      )
    else
      mail(
        to: @user.email,
        subject: options.fetch(:subject, 'New Notification')
      )
    end
  end

  def bulk_email(recipients, subject, body, options = {})
    if use_sendgrid?
      send_bulk_via_sendgrid(
        recipients: recipients,
        subject: subject,
        html_content: body,
        categories: options.fetch(:categories, ['bulk']),
        batch_size: options.fetch(:batch_size, 1000)
      )
    else
      recipients.each do |recipient|
        @body = body
        mail(to: recipient[:email], subject: subject).deliver_now
      end
    end
  end

  private

  def use_sendgrid?
    ENV['SENDGRID_API_KEY'].present? && !Rails.env.test?
  end

  def sendgrid_api_key
    ENV.fetch('SENDGRID_API_KEY') do
      raise 'SENDGRID_API_KEY environment variable is not set'
    end
  end

  def from_email
    ENV.fetch('SENDGRID_FROM_EMAIL', 'noreply@example.com')
  end

  def from_name
    ENV.fetch('SENDGRID_FROM_NAME', 'Application')
  end

  def send_via_sendgrid(params)
    mail_object = SendGrid::Mail.new

    mail_object.from = Email.new(email: from_email, name: from_name)

    personalization = Personalization.new
    personalization.add_to(Email.new(email: params[:to]))

    if params[:cc].present?
      Array(params[:cc]).each do |cc_email|
        personalization.add_cc(Email.new(email: cc_email))
      end
    end

    if params[:bcc].present?
      Array(params[:bcc]).each do |bcc_email|
        personalization.add_bcc(Email.new(email: bcc_email))
      end
    end

    personalization.subject = params[:subject]

    if params[:dynamic_template_data].present?
      params[:dynamic_template_data].each do |key, value|
        personalization.add_dynamic_template_data(key.to_s => value)
      end
    end

    if params[:custom_args].present?
      params[:custom_args].each do |key, value|
        personalization.add_custom_arg(CustomArg.new(key: key.to_s, value: value.to_s))
      end
    end

    mail_object.add_personalization(personalization)

    if params[:template_id].present?
      mail_object.template_id = params[:template_id]
    else
      if params[:html_content].present?
        mail_object.add_content(Content.new(type: 'text/html', value: params[:html_content]))
      end
      if params[:plain_content].present?
        mail_object.add_content(Content.new(type: 'text/plain', value: params[:plain_content]))
      end
    end

    if params[:categories].present?
      Array(params[:categories]).each do |category_name|
        mail_object.add_category(Category.new(name: category_name))
      end
    end

    if params[:attachments].present?
      params[:attachments].each do |attachment_data|
        attachment = Attachment.new
        attachment.content = Base64.strict_encode64(attachment_data[:content])
        attachment.type = attachment_data[:type] || 'application/octet-stream'
        attachment.filename = attachment_data[:filename]
        attachment.disposition = attachment_data[:disposition] || 'attachment'
        mail_object.add_attachment(attachment)
      end
    end

    tracking_settings = TrackingSettings.new
    click_tracking = ClickTracking.new
    click_tracking.enable = ENV.fetch('SENDGRID_CLICK_TRACKING', 'true') == 'true'
    tracking_settings.click_tracking = click_tracking

    open_tracking = OpenTracking.new
    open_tracking.enable = ENV.fetch('SENDGRID_OPEN_TRACKING', 'true') == 'true'
    tracking_settings.open_tracking = open_tracking

    mail_object.tracking_settings = tracking_settings

    if ENV['SENDGRID_UNSUBSCRIBE_GROUP_ID'].present?
      asm = ASM.new
      asm.group_id = ENV['SENDGRID_UNSUBSCRIBE_GROUP_ID'].to_i
      mail_object.asm = asm
    end

    deliver_sendgrid_mail(mail_object)
  end

  def send_bulk_via_sendgrid(params)
    recipients = params[:recipients]
    batch_size = params[:batch_size]

    recipients.each_slice(batch_size) do |batch|
      mail_object = SendGrid::Mail.new
      mail_object.from = Email.new(email: from_email, name: from_name)

      batch.each do |recipient|
        personalization = Personalization.new
        personalization.add_to(Email.new(
          email: recipient[:email],
          name: recipient[:name]
        ))
        personalization.subject = params[:subject]

        if recipient[:dynamic_data].present?
          recipient[:dynamic_data].each do |key, value|
            personalization.add_dynamic_template_data(key.to_s => value)
          end
        end

        mail_object.add_personalization(personalization)
      end

      if params[:html_content].present?
        mail_object.add_content(Content.new(type: 'text/html', value: params[:html_content]))
      end

      if params[:categories].present?
        Array(params[:categories]).each do |category_name|
          mail_object.add_category(Category.new(name: category_name))
        end
      end

      deliver_sendgrid_mail(mail_object)
    end
  end

  def deliver_sendgrid_mail(mail_object)
    sg = SendGrid::API.new(api_key: sendgrid_api_key)
    response = sg.client.mail._('send').post(request_body: mail_object.to_json)

    unless response.status_code.to_i.between?(200, 299)
      error_message = "SendGrid delivery failed with status #{response.status_code}: #{response.body}"
      Rails.logger.error(error_message)
      raise SendGridDeliveryError, error_message
    end

    Rails.logger.info("SendGrid email delivered successfully. Status: #{response.status_code}")
    response
  rescue StandardError => e
    Rails.logger.error("SendGrid delivery error: #{e.message}")
    raise if e.is_a?(SendGridDeliveryError)

    raise SendGridDeliveryError, "Failed to deliver email via SendGrid: #{e.message}"
  end

  class SendGridDeliveryError < StandardError; end
end